#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[1001];
        int n;
        scanf("%s %d", s, &n);
        int len = strlen(s);
        int count = 0;
        for (int i = 1; i <= len * n; i++) {
            int a = 0, b = 0;
            for (int j = 0; j < i; j++) {
                if (s[j % len] == 'a') a++;
                else b++;
            }
            if (a > b) count++;
        }
        printf("%d\n", count);
    }
    return 0;
}

