import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int n = sc.nextInt();
            int len = s.length();
            int count = 0;
            for (int i = 1; i <= len * n; i++) {
                int a = 0, b = 0;
                for (int j = 0; j < i; j++) {
                    if (s.charAt(j % len) == 'a') a++;
                    else b++;
                }
                if (a > b) count++;
            }
            System.out.println(count);
        }
    }
}

